SELECT zones.zone_name, COUNT(zones.region_id) AS num_regions
FROM zones
GROUP BY zones.zone_name;

SELECT DISTINCT up.user_id, up.variable_id
FROM user_permissions up
WHERE up.read_access = 1;

SELECT r.region_name
FROM regions r
WHERE r.population / r.area > (SELECT AVG(population / area) FROM regions);

SELECT unit AS unit_of_measurement
FROM data_variables
WHERE variable_id = 1;

SELECT region_name, population 
FROM regions 
WHERE region_id = (SELECT region_id FROM zones WHERE zone_id = 1);

SELECT zones.zone_name, regions.region_name 
FROM zones 
INNER JOIN regions ON zones.region_id = regions.region_id;

SELECT region_name
FROM regions R
WHERE R.area > (
    SELECT MAX(area) 
    FROM zones
);
